function StatusMessage(props) {
  // Early returns for different states
  if (props.isLoading) {
    return 'Loading...';
  }

  if (props.error) {
    return 'Error: ' + props.error;
  }

  if (!props.data) {
    return 'No data available';
  }

  return 'Data: ' + props.data;
}

