exercises.solution:
function processOrder(order) {
  if (!order) return 'Error: No order provided';
  if (!order.items || order.items.length === 0) return 'Error: Order has no items';
  if (order.total <= 0) return 'Error: Invalid order total';
  if (order.paymentMethod !== 'card' && order.paymentMethod !== 'cash') return 'Error: Invalid payment method';

  return 'Order confirmed: ' + order.items.length + ' items, $' + order.total + ' via ' + order.paymentMethod;
}

console.log(processOrder(null));
