function createItemManager() {
  let items = [];
  let nextId = 1;

  return {
    addItem(text) {
      items = [...items, { id: nextId++, text }];
    },
    removeItem(id) {
      items = items.filter(item => item.id !== id);
    },
    getItems() {
      return items;
    }
  };
}

